package com.example.documentviewerapp;

import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.provider.OpenableColumns;
import android.database.Cursor;
import android.widget.TextView;

import androidx.appcompat.app.AppCompatActivity;

public class DocumentViewerActivity extends AppCompatActivity {

    private TextView documentTitleTextView;
    private TextView documentUriTextView;
    private TextView documentMimeTypeTextView;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_document_viewer);

        documentTitleTextView = findViewById(R.id.documentTitleTextView);
        documentUriTextView = findViewById(R.id.documentUriTextView);
        documentMimeTypeTextView = findViewById(R.id.documentMimeTypeTextView);

        Intent intent = getIntent();
        if (intent != null && Intent.ACTION_VIEW.equals(intent.getAction())) {
            Uri uri = intent.getData();
            String mimeType = intent.getType();

            if (uri != null) {
                documentUriTextView.setText("URI: " + uri.toString());
                documentMimeTypeTextView.setText("Mime Type: " + (mimeType != null ? mimeType : "Unknown"));

                String fileName = getFileName(uri);
                if (fileName != null) {
                    documentTitleTextView.setText(fileName);
                } else {
                    documentTitleTextView.setText("Document Viewer");
                }

                // In a real application, you would use the 'uri' and 'mimeType'
                // to load and display the actual document content here.
                // For example:
                // if (mimeType != null && mimeType.startsWith("image/")) {
                //     // Load image into an ImageView
                // } else if (mimeType != null && mimeType.equals("application/pdf")) {
                //     // Use a PDF rendering library
                // }
            } else {
                documentTitleTextView.setText("No Document URI Found");
                documentUriTextView.setText("URI: N/A");
                documentMimeTypeTextView.setText("Mime Type: N/A");
            }
        } else {
            documentTitleTextView.setText("No VIEW Intent Received");
            documentUriTextView.setText("URI: N/A");
            documentMimeTypeTextView.setText("Mime Type: N/A");
        }
    }

    /**
     * Helper method to get the file name from a content URI.
     * Works for both content:// and file:// URIs.
     */
    private String getFileName(Uri uri) {
        String result = null;
        if (uri.getScheme().equals("content")) {
            Cursor cursor = getContentResolver().query(uri, null, null, null, null);
            try {
                if (cursor != null && cursor.moveToFirst()) {
                    int nameIndex = cursor.getColumnIndex(OpenableColumns.DISPLAY_NAME);
                    if (nameIndex != -1) {
                        result = cursor.getString(nameIndex);
                    }
                }
            } finally {
                if (cursor != null) {
                    cursor.close();
                }
            }
        }
        if (result == null) {
            result = uri.getPath();
            int cut = result.lastIndexOf('/');
            if (cut != -1) {
                result = result.substring(cut + 1);
            }
        }
        return result;
    }
}

